enum TestAction {
    Marker(String),
    Command(Vec<String>),
    CheckedCommand {
        args: Vec<String>,
        label: String,
        accept_nonzero: bool,
    },
}

#[unsafe(no_mangle)]
fn main() {
    // Create a init process
    axprocess::Process::new_init(axtask::current().id().as_u64() as _).build();
    prepare_runtime_files();

    let testcases = if option_env!("OSCOMP_RUNTIME_DISCOVERY") == Some("1") {
        discover_testcases()
    } else {
        configured_testcases()
    };

    for testcase in testcases {
        match testcase {
            TestAction::Marker(marker) => ax_println!("{marker}"),
            TestAction::Command(args) => {
                run_command(&args);
            }
            TestAction::CheckedCommand {
                args,
                label,
                accept_nonzero,
            } => {
                let success = run_command(&args).is_some_and(|code| code == 0 || accept_nonzero);
                ax_println!("{label} {}", if success { "success" } else { "fail" });
            }
        }
    }

    ax_println!("#### OS COMP TESTS FINISHED ####");
    axhal::misc::terminate();
}

fn run_command(args: &[String]) -> Option<i32> {
    info!("Running user task: {:?}", args);
    let bin_dir = args[0]
        .rsplit_once('/')
        .map_or("/", |(dir, _)| if dir.is_empty() { "/" } else { dir });
    let envs = vec![
        format!("PATH={bin_dir}:/bin:/usr/bin"),
        format!("LD_LIBRARY_PATH={bin_dir}:{bin_dir}/lib:/lib:/lib64:/musl/lib:/glibc/lib"),
    ];
    match entry::run_user_app(args, &envs) {
        Ok(exit_code) => {
            info!("User task {:?} exited with code: {:?}", args, exit_code);
            exit_code
        }
        Err(err) => {
            error!("Failed to run user task {:?}: {}", args, err);
            None
        }
    }
}

fn configured_testcases() -> Vec<TestAction> {
    option_env!("AX_TESTCASES_LIST")
        .unwrap_or_else(|| "Please specify the testcases list by making user_apps")
        .split(',')
        .filter(|testcase| !testcase.is_empty())
        .filter_map(|testcase| {
            shlex::split(testcase).or_else(|| {
                error!("Failed to parse testcase: {:?}", testcase);
                None
            })
        })
        .filter(|args| !args.is_empty())
        .map(TestAction::Command)
        .collect()
}

