            pid,
            parent: None,
            group,
            data: None,
            init: true,
        }
    }

    pub fn fork(self: &Arc<Self>, pid: Pid) -> ProcessBuilder {
        ProcessBuilder {
            pid,
            parent: Some(self.clone()),
            group: self.group(),
            data: None,
            init: false,
        }
    }

    pub fn new_thread(self: &Arc<Self>, tid: Pid) -> ThreadBuilder {
        ThreadBuilder {
            tid,
            process: self.clone(),
            data: None,
        }
    }

    pub fn pid(&self) -> Pid {
        self.pid
    }

    pub fn is_init(&self) -> bool {
        self.init
    }

    pub fn parent(&self) -> Option<Arc<Process>> {
        self.parent.lock().as_ref().and_then(Weak::upgrade)
    }

    pub fn children(&self) -> Vec<Arc<Process>> {
        self.children
            .lock()
            .iter()
            .filter(|child| !child.freed.load(Ordering::Acquire))
            .cloned()
            .collect()
    }

    pub fn group(&self) -> Arc<ProcessGroup> {
        self.group.clone()
    }

    pub fn session(&self) -> Arc<Session> {
        self.group.session()
    }

    pub fn threads(&self) -> Vec<Arc<Thread>> {
        self.threads
            .lock()
            .iter()
            .filter_map(Weak::upgrade)
            .collect()
    }

    pub fn data<T: Any + Send + Sync>(&self) -> Option<&T> {
        self.data.get()?.downcast_ref::<T>()
    }

    pub fn exit(&self) {
        self.zombie.store(true, Ordering::Release);
    }

    pub fn group_exit(&self) {
        self.group_exited.store(true, Ordering::Release);
    }

    pub fn is_group_exited(&self) -> bool {
        self.group_exited.load(Ordering::Acquire)
    }

    pub fn is_zombie(&self) -> bool {
        self.zombie.load(Ordering::Acquire)
    }

    pub fn free(&self) {
        self.freed.store(true, Ordering::Release);
        if let Some(parent) = self.parent() {
            parent.children.lock().retain(|child| child.pid != self.pid);
        }
    }

    pub fn exit_code(&self) -> i32 {
        self.exit_code.load(Ordering::Acquire)
    }
