pub struct ProcessBuilder {
    pid: Pid,
    parent: Option<Arc<Process>>,
    group: Arc<ProcessGroup>,
    data: Option<Box<DynData>>,
    init: bool,
}

impl ProcessBuilder {
    pub fn data<T: Any + Send + Sync>(mut self, data: T) -> Self {
        self.data = Some(Box::new(data));
        self
    }

    pub fn build(self) -> Arc<Process> {
        let process = Arc::new(Process {
            pid: self.pid,
            parent: Mutex::new(self.parent.as_ref().map(Arc::downgrade)),
            children: Mutex::new(Vec::new()),
            group: self.group,
            threads: Mutex::new(Vec::new()),
            data: Once::new(),
            zombie: AtomicBool::new(false),
            freed: AtomicBool::new(false),
            group_exited: AtomicBool::new(false),
            exit_code: AtomicI32::new(0),
            init: self.init,
        });

        if let Some(data) = self.data {
            process.data.call_once(|| data);
        }
        if let Some(parent) = self.parent {
            parent.children.lock().push(process.clone());
        }
        process.group.add_process(&process);
        if self.init {
            INIT_PROC.call_once(|| process.clone());
        }
        process
    }
}

pub struct Thread {
