    pub fn process_ref(&self) -> &Process {
        &self.process
    }

    pub fn data<T: Any + Send + Sync>(&self) -> Option<&T> {
        self.data.get()?.downcast_ref::<T>()
    }

    pub fn exit(&self, exit_code: i32) -> bool {
        self.exit_code.store(exit_code, Ordering::Release);
        self.zombie.store(true, Ordering::Release);
        self.process.exit_code.store(exit_code, Ordering::Release);
        self.process
            .threads()
            .iter()
            .all(|thread| thread.zombie.load(Ordering::Acquire))
    }
}

