const FD_CLOEXEC: u32 = 1;
const SFD_NONBLOCK: u32 = O_NONBLOCK;
const SFD_CLOEXEC: u32 = O_CLOEXEC;
const SIGNALFD_SIGINFO_SIZE: usize = 128;

struct SignalFd {
    mask: SpinMutex<SignalSet>,
    nonblocking: AtomicBool,
    cloexec: AtomicBool,
}

impl SignalFd {
    fn new(mask: SignalSet, flags: u32) -> Self {
        Self {
            mask: SpinMutex::new(mask),
            nonblocking: AtomicBool::new(flags & SFD_NONBLOCK != 0),
            cloexec: AtomicBool::new(flags & SFD_CLOEXEC != 0),
        }
    }

    fn update(&self, mask: SignalSet, flags: u32) {
        *self.mask.lock() = mask;
        self.nonblocking
            .store(flags & SFD_NONBLOCK != 0, Ordering::Relaxed);
        self.cloexec
            .store(flags & SFD_CLOEXEC != 0, Ordering::Relaxed);
    }
}

impl FileLike for SignalFd {
    fn read(&self, buf: &mut [u8]) -> LinuxResult<usize> {
        if buf.len() < SIGNALFD_SIGINFO_SIZE {
            return Err(LinuxError::EINVAL);
        }
        let mask = *self.mask.lock();
        let timeout = if self.nonblocking.load(Ordering::Relaxed) {
            Some(Duration::ZERO)
        } else {
            None
        };

        let Some(info) = current()
            .task_ext()
            .thread_data()
            .signal
            .wait_timeout(mask, timeout)
        else {
            return Err(LinuxError::EAGAIN);
        };

        let out = &mut buf[..SIGNALFD_SIGINFO_SIZE];
        out.fill(0);
        write_u32(out, 0, info.signo() as u32);
        write_i32(out, 8, info.code());
        Ok(SIGNALFD_SIGINFO_SIZE)
    }

    fn write(&self, _buf: &[u8]) -> LinuxResult<usize> {
        Err(LinuxError::EINVAL)
    }

    fn stat(&self) -> LinuxResult<Kstat> {
        Ok(Kstat::default())
    }

    fn into_any(self: Arc<Self>) -> Arc<dyn Any + Send + Sync> {
        self
    }

    fn poll(&self) -> LinuxResult<PollState> {
        let pending = current().task_ext().thread_data().signal.pending();
        Ok(PollState {
            readable: pending.intersects(*self.mask.lock()),
            writable: false,
        })
    }

    fn set_nonblocking(&self, nonblocking: bool) -> LinuxResult {
        self.nonblocking.store(nonblocking, Ordering::Relaxed);
        Ok(())
    }

    fn descriptor_flags(&self) -> LinuxResult<u32> {
        Ok(if self.cloexec.load(Ordering::Relaxed) {
            FD_CLOEXEC
        } else {
            0
        })
    }

    fn status_flags(&self) -> LinuxResult<u32> {
        Ok(if self.nonblocking.load(Ordering::Relaxed) {
            O_NONBLOCK
        } else {
            0
        })
    }
}

fn write_u32(buf: &mut [u8], offset: usize, value: u32) {
    buf[offset..offset + 4].copy_from_slice(&value.to_ne_bytes());
}

fn write_i32(buf: &mut [u8], offset: usize, value: i32) {
    buf[offset..offset + 4].copy_from_slice(&value.to_ne_bytes());
}

fn check_sigset_size(size: usize) -> LinuxResult<()> {
    if size != size_of::<SignalSet>() {
        return Err(LinuxError::EINVAL);
    }
    Ok(())
}

fn parse_signo(signo: u32) -> LinuxResult<Signo> {
    Signo::from_repr(signo as u8).ok_or(LinuxError::EINVAL)
}

pub fn sys_rt_sigprocmask(
    how: i32,
    set: UserConstPtr<SignalSet>,
    oldset: UserPtr<SignalSet>,
    sigsetsize: usize,
) -> LinuxResult<isize> {
    check_sigset_size(sigsetsize)?;

    current()
        .task_ext()
        .thread_data()
        .signal
        .with_blocked_mut::<LinuxResult<_>>(|blocked| {
            if let Some(oldset) = nullable!(oldset.get_as_mut())? {
                *oldset = *blocked;
            }

            if let Some(set) = nullable!(set.get_as_ref())? {
                match how as u32 {
                    SIG_BLOCK => *blocked |= *set,
                    SIG_UNBLOCK => *blocked &= !*set,
                    SIG_SETMASK => *blocked = *set,
                    _ => return Err(LinuxError::EINVAL),
                }
            }
            Ok(())
        })?;

    Ok(0)
}

pub fn sys_rt_sigaction(
    signo: u32,
    act: UserConstPtr<kernel_sigaction>,
    oldact: UserPtr<kernel_sigaction>,
    sigsetsize: usize,
) -> LinuxResult<isize> {
    check_sigset_size(sigsetsize)?;

    let signo = parse_signo(signo)?;
    if matches!(signo, Signo::SIGKILL | Signo::SIGSTOP) {
        return Err(LinuxError::EINVAL);
    }

    let curr = current();
    let mut actions = curr.task_ext().process_data().signal.actions.lock();
    if let Some(oldact) = nullable!(oldact.get_as_mut())? {
        actions[signo].to_ctype(oldact);
    }
    if let Some(act) = nullable!(act.get_as_ref())? {
        actions[signo] = (*act).try_into()?;
    }
    Ok(0)
}

pub fn sys_rt_sigpending(set: UserPtr<SignalSet>, sigsetsize: usize) -> LinuxResult<isize> {
    check_sigset_size(sigsetsize)?;
    *set.get_as_mut()? = current().task_ext().thread_data().signal.pending();
    Ok(0)
}

pub fn sys_signalfd4(
    fd: i32,
    mask: UserConstPtr<SignalSet>,
    sigsetsize: usize,
    flags: u32,
) -> LinuxResult<isize> {
    check_sigset_size(sigsetsize)?;
    if mask.is_null() {
        return Err(LinuxError::EFAULT);
    }
    if flags & !(SFD_NONBLOCK | SFD_CLOEXEC) != 0 {
        return Err(LinuxError::EINVAL);
    }

    let mask = *mask.get_as_ref()?;
    if fd >= 0 {
        let signalfd = SignalFd::from_fd(fd)?;
        signalfd.update(mask, flags);
