    buf: UserConstPtr<u8>,
    len: usize,
    offset: __kernel_off_t,
) -> LinuxResult<isize> {
    if offset < 0 {
        return Err(LinuxError::EINVAL);
    }
    let buf = buf.get_as_slice(len)?;
    Ok(get_file_like(fd)?.write_at(offset as _, buf)? as _)
}

pub fn sys_writev(fd: i32, iov: UserConstPtr<iovec>, iocnt: usize) -> LinuxResult<isize> {
    if !(0..=1024).contains(&iocnt) {
        return Err(LinuxError::EINVAL);
    }

    let iovs = iov.get_as_slice(iocnt)?;
    let mut ret = 0;
    for iov in iovs {
        if iov.iov_len == 0 {
            continue;
        }
        let buf = UserConstPtr::<u8>::from(iov.iov_base as usize);
        let buf = buf.get_as_slice(iov.iov_len as _)?;
        debug!(
            "sys_writev <= fd: {}, buf: {:p}, len: {}",
            fd,
            buf.as_ptr(),
            buf.len()
        );

        let written = get_file_like(fd)?.write(buf)?;
        ret += written as isize;

        if written < buf.len() {
            break;
        }
    }

    Ok(ret)
}

pub fn sys_pwritev(
    fd: i32,
    iov: UserConstPtr<iovec>,
    iocnt: usize,
    offset: __kernel_off_t,
) -> LinuxResult<isize> {
    if offset < 0 || !(0..=1024).contains(&iocnt) {
        return Err(LinuxError::EINVAL);
    }

    let iovs = iov.get_as_slice(iocnt)?;
    let file = get_file_like(fd)?;

    let mut ret = 0;
    for iov in iovs {
        if iov.iov_len == 0 {
            continue;
        }
        let buf = UserConstPtr::<u8>::from(iov.iov_base as usize).get_as_slice(iov.iov_len as _)?;
        let written = file.write_at(offset as u64 + ret as u64, buf)?;
        ret += written as isize;
        if written < buf.len() {
            break;
        }
    }
    Ok(ret)
}

pub fn sys_pwritev2(
    fd: i32,
    iov: UserConstPtr<iovec>,
    iocnt: usize,
    offset_low: usize,
    offset_high_or_flags: usize,
    flags: usize,
) -> LinuxResult<isize> {
    let offset = vectored_offset(offset_low, offset_high_or_flags, flags)?;
    sys_pwritev(fd, iov, iocnt, offset)
}

fn vectored_offset(
    offset_low: usize,
    offset_high_or_flags: usize,
    flags: usize,
) -> LinuxResult<__kernel_off_t> {
    if flags == 0 {
        if offset_low > __kernel_off_t::MAX as usize {
            return Err(LinuxError::EINVAL);
        }
        return Ok(offset_low as __kernel_off_t);
    }

    let offset = ((offset_high_or_flags as u64) << 32) | (offset_low as u32 as u64);
    if offset > __kernel_off_t::MAX as u64 {
        return Err(LinuxError::EINVAL);
    }
    Ok(offset as __kernel_off_t)
}

pub fn sys_sendfile(
    out_fd: c_int,
    in_fd: c_int,
    offset: UserPtr<__kernel_off_t>,
    count: usize,
) -> LinuxResult<isize> {
    let in_file = File::from_fd(in_fd)?;
    let mut in_file = in_file.inner();
    let out_file = get_file_like(out_fd)?;

    let mut copied = 0usize;
    let original = in_file.seek(SeekFrom::Current(0))?;
    let mut explicit_offset = None;
    if !offset.is_null() {
        let value = *offset.get_as_mut()?;
        if value < 0 {
            return Err(LinuxError::EINVAL);
        }
        in_file.seek(SeekFrom::Start(value as _))?;
        explicit_offset = Some(value);
    }

    let mut buf = [0u8; 4096];
    while copied < count {
        let len = core::cmp::min(buf.len(), count - copied);
        let read = in_file.read(&mut buf[..len])?;
        if read == 0 {
            break;
        }
        let written = out_file.write(&buf[..read])?;
        copied += written;
        if written < read {
            break;
        }
    }

    if let Some(start) = explicit_offset {
        *offset.get_as_mut()? = start + copied as __kernel_off_t;
        in_file.seek(SeekFrom::Start(original))?;
    }

    Ok(copied as _)
}

pub fn sys_copy_file_range(
    in_fd: c_int,
    in_offset: UserPtr<__kernel_off_t>,
    out_fd: c_int,
    out_offset: UserPtr<__kernel_off_t>,
    len: usize,
    flags: usize,
) -> LinuxResult<isize> {
    if flags != 0 {
        return Err(LinuxError::EINVAL);
    }
    copy_between_fds(in_fd, in_offset, out_fd, out_offset, len)
}

pub fn sys_splice(
    fd_in: c_int,
    off_in: UserPtr<__kernel_off_t>,
    fd_out: c_int,
    off_out: UserPtr<__kernel_off_t>,
    len: usize,
    flags: usize,
) -> LinuxResult<isize> {
    if flags & !SPLICE_ALLOWED_FLAGS != 0 {
        return Err(LinuxError::EINVAL);
    }

    let in_is_pipe = Pipe::from_fd(fd_in).is_ok();
    let out_is_pipe = Pipe::from_fd(fd_out).is_ok();
    if !in_is_pipe && !out_is_pipe {
        return Err(LinuxError::EINVAL);
    }
    if (in_is_pipe && !off_in.is_null()) || (out_is_pipe && !off_out.is_null()) {
        return Err(LinuxError::ESPIPE);
    }

    copy_between_fds(fd_in, off_in, fd_out, off_out, len)
}

