const FUTEX_TID_MASK: u32 = 0x3fff_ffff;

// Robust-list traversal is adapted from StarryOS; see ATTRIBUTION.md.
fn mark_robust_futex_owner_dead(entry: usize, offset: isize, tid: u32) -> axerrno::LinuxResult {
    let futex_addr = entry
        .checked_add_signed(offset)
        .ok_or(axerrno::LinuxError::EINVAL)?;
    let futex_ptr = UserPtr::<u32>::from(futex_addr).get_as_mut()? as *mut u32;
    // A futex word is naturally aligned and may be updated concurrently by userspace.
    let futex = unsafe { &*futex_ptr.cast::<AtomicU32>() };
    let mut value = futex.load(Ordering::Acquire);
    let had_waiters = loop {
        if value & FUTEX_TID_MASK != tid & FUTEX_TID_MASK {
            return Ok(());
        }
        let new_value = (value & FUTEX_WAITERS) | FUTEX_OWNER_DIED;
        match futex.compare_exchange(value, new_value, Ordering::AcqRel, Ordering::Acquire) {
            Ok(_) => break value & FUTEX_WAITERS != 0,
            Err(actual) => value = actual,
        }
    };

    if had_waiters {
        let curr = current();
        if let Some(wait_queue) = curr.task_ext().process_data().futex_table.get(futex_addr) {
            wait_queue.notify_one(false);
        }
    }
    Ok(())
}

fn exit_robust_list(head_addr: usize, tid: u32) -> axerrno::LinuxResult {
    const ROBUST_LIST_LIMIT: usize = 2048;

    let head = *UserConstPtr::<robust_list_head>::from(head_addr).get_as_ref()?;
    let sentinel = head_addr
        .checked_add(core::mem::offset_of!(robust_list_head, list))
        .ok_or(axerrno::LinuxError::EINVAL)?;
    let pending = head.list_op_pending as usize;
    let mut entry = head.list.next as usize;

    for _ in 0..ROBUST_LIST_LIMIT {
        if entry == sentinel {
            break;
        }
        if entry == 0 {
            return Err(axerrno::LinuxError::EFAULT);
        }
        let next = UserConstPtr::<robust_list>::from(entry).get_as_ref()?.next as usize;
        if entry != pending {
            mark_robust_futex_owner_dead(entry, head.futex_offset as isize, tid)?;
        }
        entry = next;
        axtask::yield_now();
    }

    if entry != sentinel {
        return Err(axerrno::LinuxError::ELOOP);
    }
    if pending != 0 {
        mark_robust_futex_owner_dead(pending, head.futex_offset as isize, tid)?;
    }
    Ok(())
}

pub fn do_exit(exit_code: i32, group_exit: bool) -> ! {
    let curr = current();
    let curr_ext = curr.task_ext();

    let thread = &curr_ext.thread;
    info!("{:?} exit with code: {}", thread, exit_code);

    let clear_child_tid = UserPtr::<Pid>::from(curr_ext.thread_data().clear_child_tid());
    if let Ok(clear_tid) = clear_child_tid.get_as_mut() {
        *clear_tid = 0;

        let guard = curr_ext
            .process_data()
            .futex_table
            .get(clear_tid as *const _ as usize);
        if let Some(futex) = guard {
            futex.notify_one(false);
        }
        axtask::yield_now();
    }

    let robust_list_head = curr_ext.thread_data().robust_list_head();
    if robust_list_head != 0
        && let Err(err) = exit_robust_list(robust_list_head, curr.id().as_u64() as u32)
    {
        warn!("failed to process robust futex list: {err:?}");
    }

    let process = thread.process();
    if thread.exit(exit_code) {
        process.exit();
        if let Some(data) = process.data::<ProcessData>()
            && Arc::strong_count(&data.aspace) == 1
            && let Err(err) = data.aspace.lock().unmap_user_areas()
        {
            warn!("failed to release exiting process address space: {err:?}");
        }
        if let Some(parent) = process.parent() {
            if let Some(signo) = process.data::<ProcessData>().and_then(|it| it.exit_signal) {
                let _ = send_signal_process(&parent, SignalInfo::new(signo, SI_KERNEL as _));
            }
            if let Some(data) = parent.data::<ProcessData>() {
                data.child_exit_wq.notify_all(false)
            }
        }

        // TODO: clear namespace resources
        // FIXME: axns should drop all the resources
        FD_TABLE.clear();
    }
    if group_exit && !process.is_group_exited() {
        process.group_exit();
        let sig = SignalInfo::new(Signo::SIGKILL, SI_KERNEL as _);
        for thr in process.threads() {
            let _ = send_signal_thread(&thr, sig.clone());
        }
    }
    // axtask::exit switches away without unwinding this stack frame. Release the
    // cloned process reference explicitly so the task GC can drop ProcessData.
    drop(process);
    axtask::exit(exit_code)
}

pub fn sys_exit(exit_code: i32) -> ! {
    do_exit(exit_code << 8, false)
}

pub fn sys_exit_group(exit_code: i32) -> ! {
    do_exit(exit_code << 8, true)
}

