bitflags! {
    #[derive(Debug)]
    struct WaitOptions: u32 {
        /// Do not block when there are no processes wishing to report status.
        const WNOHANG = WNOHANG;
        /// Report the status of selected processes which are stopped due to a
        /// `SIGTTIN`, `SIGTTOU`, `SIGTSTP`, or `SIGSTOP` signal.
        const WUNTRACED = WUNTRACED;
        /// Report the status of selected processes which have terminated.
        const WEXITED = WEXITED;
        /// Report the status of selected processes that have continued from a
        /// job control stop by receiving a `SIGCONT` signal.
        const WCONTINUED = WCONTINUED;
        /// Don't reap, just poll status.
        const WNOWAIT = WNOWAIT;

        /// Don't wait on children of other threads in this group
        const WNOTHREAD = __WNOTHREAD;
        /// Wait on all children, regardless of type
        const WALL = __WALL;
        /// Wait for "clone" children only.
        const WCLONE = __WCLONE;
    }
}

#[derive(Debug, Clone, Copy)]
enum WaitPid {
    /// Wait for any child process
    Any,
    /// Wait for the child whose process ID is equal to the value.
    Pid(Pid),
    /// Wait for any child process whose process group ID is equal to the value.
    Pgid(Pid),
}

const P_ALL: i32 = 0;
const P_PID: i32 = 1;
const P_PGID: i32 = 2;
const P_PIDFD: i32 = 3;
const SIGINFO_SIZE: usize = 128;
const SIGINFO_PID_OFFSET: usize = 16;
const SIGINFO_STATUS_OFFSET: usize = 24;

impl WaitPid {
    fn apply(&self, child: &Arc<Process>) -> bool {
        match self {
            WaitPid::Any => true,
            WaitPid::Pid(pid) => child.pid() == *pid,
            WaitPid::Pgid(pgid) => child.group().pgid() == *pgid,
        }
    }
}

pub fn sys_waitpid(pid: i32, exit_code_ptr: UserPtr<i32>, options: u32) -> LinuxResult<isize> {
    let options = WaitOptions::from_bits_truncate(options);
    info!("sys_waitpid <= pid: {:?}, options: {:?}", pid, options);

    let curr = current();
    let proc_data = curr.task_ext().process_data();
    let process = curr.task_ext().thread.process();

    let pid = if pid == -1 {
        WaitPid::Any
    } else if pid == 0 {
        WaitPid::Pgid(process.group().pgid())
    } else if pid > 0 {
        WaitPid::Pid(pid as _)
    } else {
        WaitPid::Pgid(-pid as _)
    };

    let children = process
        .children()
        .into_iter()
        .filter(|child| pid.apply(child))
        .filter(|child| {
            options.contains(WaitOptions::WALL)
                || (options.contains(WaitOptions::WCLONE)
                    == child.data::<ProcessData>().unwrap().is_clone_child())
        })
        .collect::<Vec<_>>();
    if children.is_empty() {
        return Err(LinuxError::ECHILD);
    }

    let exit_code = nullable!(exit_code_ptr.get_as_mut())?;
    loop {
        if let Some(child) = children.iter().find(|child| child.is_zombie()) {
            if !options.contains(WaitOptions::WNOWAIT) {
                child.free();
            }
            if let Some(exit_code) = exit_code {
                *exit_code = child.exit_code();
            }
            return Ok(child.pid() as _);
        } else if options.contains(WaitOptions::WNOHANG) {
            return Ok(0);
        } else {
            proc_data.child_exit_wq.wait();
        }
    }
}

pub fn sys_waitid(
    idtype: i32,
    id: i32,
    infop: UserPtr<u8>,
    options: u32,
    _rusage: usize,
) -> LinuxResult<isize> {
    let options = WaitOptions::from_bits_truncate(options);
    if !options.contains(WaitOptions::WEXITED)
        || options.intersects(WaitOptions::WUNTRACED | WaitOptions::WCONTINUED)
    {
        return Err(LinuxError::EINVAL);
    }
    if infop.is_null() {
        return Err(LinuxError::EFAULT);
    }

    if idtype == P_PIDFD {
        let (process, nonblocking) = pidfd_process(id)?;
        return waitid_for_process(process, infop, options, nonblocking);
    }

    let curr = current();
    let process = curr.task_ext().thread.process();
    let selector = match idtype {
        P_ALL => WaitPid::Any,
        P_PID if id > 0 => WaitPid::Pid(id as Pid),
        P_PGID if id >= 0 => {
            let pgid = if id == 0 {
                process.group().pgid()
            } else {
                id as Pid
            };
            WaitPid::Pgid(pgid)
        }
        _ => return Err(LinuxError::EINVAL),
    };

    let children = process
        .children()
        .into_iter()
        .filter(|child| selector.apply(child))
        .collect::<Vec<_>>();
    if children.is_empty() {
        return Err(LinuxError::ECHILD);
    }

    loop {
        if let Some(child) = children.iter().find(|child| child.is_zombie()) {
            write_waitid_siginfo(infop, child.pid(), child.exit_code())?;
            if !options.contains(WaitOptions::WNOWAIT) {
                child.free();
            }
            return Ok(0);
        }
        if options.contains(WaitOptions::WNOHANG) {
            infop.get_as_mut_slice(SIGINFO_SIZE)?.fill(0);
            return Ok(0);
        }
        curr.task_ext().process_data().child_exit_wq.wait();
    }
}

fn waitid_for_process(
    process: Arc<Process>,
    infop: UserPtr<u8>,
    options: WaitOptions,
    nonblocking: bool,
) -> LinuxResult<isize> {
    loop {
        if process.is_zombie() {
            write_waitid_siginfo(infop, process.pid(), process.exit_code())?;
            if !options.contains(WaitOptions::WNOWAIT) {
                process.free();
            }
            return Ok(0);
        }
        if options.contains(WaitOptions::WNOHANG) {
            infop.get_as_mut_slice(SIGINFO_SIZE)?.fill(0);
            return Ok(0);
        }
        if nonblocking {
            return Err(LinuxError::EAGAIN);
        }
        current().task_ext().process_data().child_exit_wq.wait();
    }
}

fn write_waitid_siginfo(infop: UserPtr<u8>, pid: Pid, exit_code: i32) -> LinuxResult {
    let info = infop.get_as_mut_slice(SIGINFO_SIZE)?;
    info.fill(0);
    write_i32(info, 0, SIGCHLD as i32);
    write_i32(info, 8, CLD_EXITED as i32);
    write_i32(info, SIGINFO_PID_OFFSET, pid as i32);
    write_i32(info, SIGINFO_STATUS_OFFSET, exit_code >> 8);
    Ok(())
}

fn write_i32(buf: &mut [u8], offset: usize, value: i32) {
    buf[offset..offset + 4].copy_from_slice(&value.to_ne_bytes());
}

