pub fn sys_socket(domain: c_int, socket_type: c_int, protocol: c_int) -> LinuxResult<isize> {
    if !matches!(domain as u32, AF_INET | AF_INET6) {
        return Err(LinuxError::EAFNOSUPPORT);
    }

    let allowed_flags = SOCK_TYPE_MASK | O_NONBLOCK as c_int | O_CLOEXEC as c_int;
    if socket_type & !allowed_flags != 0 {
        return Err(LinuxError::EINVAL);
    }

    let socket = match socket_type & SOCK_TYPE_MASK {
        SOCK_STREAM if protocol == 0 || protocol == IPPROTO_TCP => {
            Socket::Tcp(Mutex::new(TcpSocket::new()))
        }
        SOCK_DGRAM if protocol == 0 || protocol == IPPROTO_UDP => {
            Socket::Udp(Mutex::new(UdpSocket::new()))
        }
        SOCK_STREAM | SOCK_DGRAM => return Err(LinuxError::EPROTONOSUPPORT),
        _ => return Err(LinuxError::EINVAL),
    };
    let nonblocking = socket_type & O_NONBLOCK as c_int != 0;
    if nonblocking {
        socket.set_nonblocking(true)?;
    }

    Ok(socket.add_to_fd_table()? as _)
}

pub fn sys_socketpair(
    domain: c_int,
    socket_type: c_int,
    protocol: c_int,
    sv: UserPtr<c_int>,
) -> LinuxResult<isize> {
    let allowed_flags = SOCK_TYPE_MASK | O_NONBLOCK as c_int | O_CLOEXEC as c_int;
    if socket_type & !allowed_flags != 0 {
        return Err(LinuxError::EINVAL);
    }

    let socket_type_base = socket_type & SOCK_TYPE_MASK;
    if domain as u32 != AF_UNIX {
        return match domain as u32 {
            AF_INET | AF_INET6 => match socket_type_base {
                SOCK_STREAM if protocol == 0 || protocol == IPPROTO_TCP => {
                    Err(LinuxError::EOPNOTSUPP)
                }
                SOCK_DGRAM if protocol == 0 || protocol == IPPROTO_UDP => {
                    Err(LinuxError::EOPNOTSUPP)
                }
                SOCK_STREAM | SOCK_DGRAM | SOCK_RAW => Err(LinuxError::EPROTONOSUPPORT),
                _ => Err(LinuxError::EINVAL),
            },
            _ => Err(LinuxError::EAFNOSUPPORT),
        };
    }

    if !matches!(socket_type_base, SOCK_STREAM | SOCK_DGRAM) {
        return Err(LinuxError::EINVAL);
    }
    if protocol != 0 {
        return Err(LinuxError::EPROTONOSUPPORT);
    }

    let slots = sv.get_as_mut_slice(2)?;
    let nonblocking = socket_type & O_NONBLOCK as c_int != 0;
    let cloexec = socket_type & O_CLOEXEC as c_int != 0;
    let (left, right) = UnixSocket::pair(nonblocking, cloexec);
    let left_fd = Socket::Unix(left).add_to_fd_table()?;
    let right_fd = match Socket::Unix(right).add_to_fd_table() {
        Ok(fd) => fd,
        Err(err) => {
            let _ = close_file_like(left_fd);
            return Err(err);
        }
    };
    slots[0] = left_fd;
    slots[1] = right_fd;
    Ok(0)
}

