pub fn sys_accept4(
    fd: c_int,
    addr: UserPtr<sockaddr>,
    addrlen: UserPtr<socklen_t>,
    flags: c_int,
) -> LinuxResult<isize> {
    let allowed_flags = O_NONBLOCK as c_int | O_CLOEXEC as c_int;
    if flags & !allowed_flags != 0 {
        return Err(LinuxError::EINVAL);
    }

    let tcp = Socket::from_fd(fd)?.accept()?;
    let peer = tcp.peer_addr().ok();
    let socket = Socket::Tcp(Mutex::new(tcp));
    if flags & O_NONBLOCK as c_int != 0 {
        socket.set_nonblocking(true)?;
    }
    let new_fd = socket.add_to_fd_table()?;
    if let Some(peer) = peer {
        write_sockaddr(addr, addrlen, peer)?;
    }
    Ok(new_fd as _)
}

