use axerrno::{LinuxError, LinuxResult};
use axtask::{TaskExtRef, current};
use linux_raw_sys::general::{
    FUTEX_CMD_MASK, FUTEX_CMP_REQUEUE, FUTEX_REQUEUE, FUTEX_WAIT, FUTEX_WAKE, timespec,
};

use crate::{
    ptr::{UserConstPtr, UserPtr, nullable},
    time::TimeValueLike,
};

pub fn sys_futex(
    uaddr: UserConstPtr<u32>,
    futex_op: u32,
    value: u32,
    timeout: UserConstPtr<timespec>,
    uaddr2: UserPtr<u32>,
    value3: u32,
) -> LinuxResult<isize> {
    info!("futex {:?} {} {}", uaddr.address(), futex_op, value);

    let curr = current();
    let futex_table = &curr.task_ext().process_data().futex_table;

    let addr = uaddr.address().as_usize();
    let command = futex_op & (FUTEX_CMD_MASK as u32);
    match command {
        FUTEX_WAIT => {
            if *uaddr.get_as_ref()? != value {
                return Err(LinuxError::EAGAIN);
            }
            let wq = futex_table.get_or_insert(addr);

            if let Some(timeout) = nullable!(timeout.get_as_ref())? {
                wq.wait_timeout(timeout.to_time_value());
            } else {
                wq.wait();
            }

            Ok(0)
        }
        FUTEX_WAKE => {
            let wq = futex_table.get(addr);
            let mut count = 0;
            if let Some(wq) = wq {
                for _ in 0..value {
                    if !wq.notify_one(false) {
                        break;
                    }
                    count += 1;
                }
            }
            axtask::yield_now();
            Ok(count)
        }
        FUTEX_REQUEUE | FUTEX_CMP_REQUEUE => {
            if command == FUTEX_CMP_REQUEUE && *uaddr.get_as_ref()? != value3 {
                return Err(LinuxError::EAGAIN);
            }
            let value2 = timeout.address().as_usize() as u32;

            let wq = futex_table.get(addr);
            let wq2 = futex_table.get_or_insert(uaddr2.address().as_usize());

            let mut count = 0;
            if let Some(wq) = wq {
                for _ in 0..value {
                    if !wq.notify_one(false) {
                        break;
                    }
                    count += 1;
                }
                if count == value as isize {
                    count += wq.requeue(value2 as usize, &wq2) as isize;
                }
            }
            Ok(count)
        }
        _ => Err(LinuxError::ENOSYS),
    }
}

// SysV shared memory compatibility layer adapted from StarryOS:
// https://github.com/Starry-OS/StarryOS/blob/2e075accf4fb0aefdd1d252ebd9ccf29727d9923/kernel/src/syscall/ipc/shm.rs

use core::ffi::c_void;

use alloc::{collections::btree_map::BTreeMap, sync::Arc};
use axerrno::{LinuxError, LinuxResult};
use axhal::paging::{MappingFlags, PageSize};
use axmm::SharedPages;
use axtask::{TaskExtRef, current};
use memory_addr::{MemoryAddr, VirtAddr, VirtAddrRange, align_up_4k};
use spin::Mutex;

use crate::ptr::UserPtr;

const IPC_PRIVATE: i32 = 0;
const IPC_CREAT: usize = 0o1000;
const IPC_EXCL: usize = 0o2000;
const IPC_RMID: i32 = 0;

const SHM_RDONLY: u32 = 0o10000;
const SHM_RND: u32 = 0o20000;
const SHM_REMAP: u32 = 0o40000;

struct ShmSegment {
    key: i32,
    size: usize,
    pages: Arc<SharedPages>,
}

struct ShmManager {
    next_id: i32,
    by_key: BTreeMap<i32, i32>,
    by_id: BTreeMap<i32, Arc<ShmSegment>>,
}

impl ShmManager {
    const fn new() -> Self {
        Self {
            next_id: 1,
            by_key: BTreeMap::new(),
            by_id: BTreeMap::new(),
        }
    }

    fn allocate_id(&mut self) -> LinuxResult<i32> {
        let id = self.next_id;
        self.next_id = self.next_id.checked_add(1).ok_or(LinuxError::ENOSPC)?;
        Ok(id)
    }
}

static SHM_MANAGER: Mutex<ShmManager> = Mutex::new(ShmManager::new());

/// Returns or creates a SysV shared memory segment.
pub fn sys_shmget(key: i32, size: usize, shmflg: usize) -> LinuxResult<isize> {
    let mut manager = SHM_MANAGER.lock();

    if key != IPC_PRIVATE
        && let Some(id) = manager.by_key.get(&key).copied()
    {
        if shmflg & (IPC_CREAT | IPC_EXCL) == (IPC_CREAT | IPC_EXCL) {
            return Err(LinuxError::EEXIST);
        }
        let segment = manager.by_id.get(&id).ok_or(LinuxError::EINVAL)?;
        if size > segment.size {
            return Err(LinuxError::EINVAL);
        }
        return Ok(id as isize);
    }

    if key != IPC_PRIVATE && shmflg & IPC_CREAT == 0 {
        return Err(LinuxError::ENOENT);
    }

    let size = align_up_4k(size);
    if size == 0 {
        return Err(LinuxError::EINVAL);
    }

    let id = manager.allocate_id()?;
    let segment = Arc::new(ShmSegment {
        key,
        size,
        pages: Arc::new(SharedPages::new(size, PageSize::Size4K)?),
    });
    if key != IPC_PRIVATE {
        manager.by_key.insert(key, id);
    }
    manager.by_id.insert(id, segment);
    debug!("shmget: key={key} size={size:#x} id={id}");
    Ok(id as isize)
}

/// Attaches a SysV shared memory segment to the current process.
pub fn sys_shmat(shmid: i32, addr: usize, shmflg: u32) -> LinuxResult<isize> {
    if shmflg & SHM_REMAP != 0 {
        return Err(LinuxError::EINVAL);
    }

    let segment = SHM_MANAGER
        .lock()
        .by_id
        .get(&shmid)
        .cloned()
        .ok_or(LinuxError::EINVAL)?;

    let requested = if addr == 0 {
        None
    } else if shmflg & SHM_RND != 0 {
        Some(VirtAddr::from(addr).align_down_4k())
    } else {
        let addr = VirtAddr::from(addr);
        if !addr.is_aligned_4k() {
            return Err(LinuxError::EINVAL);
        }
        Some(addr)
    };

    let curr = current();
    let process_data = curr.task_ext().process_data();
    let mut aspace = process_data.aspace.lock();
    let limit = VirtAddrRange::new(aspace.base(), aspace.end());
    let start = if let Some(requested) = requested {
        match aspace.find_free_area(requested, segment.size, limit, PageSize::Size4K) {
            Some(found) if found == requested => found,
            _ => return Err(LinuxError::EINVAL),
        }
    } else {
        aspace
            .find_free_area(aspace.base(), segment.size, limit, PageSize::Size4K)
            .ok_or(LinuxError::ENOMEM)?
    };

    let mut flags = MappingFlags::USER | MappingFlags::READ;
    if shmflg & SHM_RDONLY == 0 {
        flags |= MappingFlags::WRITE;
    }
    aspace.map_shared(start, segment.size, flags, segment.pages.clone())?;
    debug!(
        "shmat: id={shmid} addr={:#x} size={:#x}",
        start.as_usize(),
        segment.size
    );
    drop(aspace);

    process_data
        .shm_attachments
        .lock()
        .insert(start.as_usize(), segment.size);
    Ok(start.as_usize() as isize)
}

/// Marks a segment for removal. Existing mappings remain valid until detached.
pub fn sys_shmctl(shmid: i32, cmd: i32, _buf: UserPtr<c_void>) -> LinuxResult<isize> {
    if cmd != IPC_RMID {
        return Err(LinuxError::EINVAL);
    }

    let mut manager = SHM_MANAGER.lock();
    let segment = manager.by_id.remove(&shmid).ok_or(LinuxError::EINVAL)?;
    if segment.key != IPC_PRIVATE && manager.by_key.get(&segment.key) == Some(&shmid) {
        manager.by_key.remove(&segment.key);
    }
    debug!("shmctl: IPC_RMID id={shmid}");
    Ok(0)
}

/// Detaches a SysV shared memory mapping from the current process.
pub fn sys_shmdt(addr: usize) -> LinuxResult<isize> {
    let curr = current();
    let process_data = curr.task_ext().process_data();
    let size = process_data
        .shm_attachments
        .lock()
        .get(&addr)
        .copied()
        .ok_or(LinuxError::EINVAL)?;

    process_data
        .aspace
        .lock()
        .unmap(VirtAddr::from(addr), size)?;
    process_data.shm_attachments.lock().remove(&addr);
    axhal::arch::flush_tlb(None);
    Ok(0)
}

