    fn read(&self, buf: &mut [u8]) -> LinuxResult<usize> {
        Ok(self.inner().read(buf)?)
    }

    fn write(&self, buf: &[u8]) -> LinuxResult<usize> {
        Ok(self.inner().write(buf)?)
    }

    fn stat(&self) -> LinuxResult<Kstat> {
        let metadata = self.inner().get_attr()?;
        let ty = metadata.file_type() as u8;
        let perm = metadata.perm().bits() as u32;

        Ok(Kstat {
            mode: ((ty as u32) << 12) | perm,
            size: metadata.size(),
            blocks: metadata.blocks(),
            blksize: 512,
            ..Default::default()
        })
    }

    fn into_any(self: Arc<Self>) -> Arc<dyn Any + Send + Sync> {
        self
    }

    fn poll(&self) -> LinuxResult<PollState> {
        Ok(PollState {
            readable: true,
            writable: true,
        })
    }

    fn set_nonblocking(&self, _nonblocking: bool) -> LinuxResult {
        Ok(())
    }

    fn read_at(&self, offset: u64, buf: &mut [u8]) -> LinuxResult<usize> {
        Ok(self.inner().read_at(offset, buf)?)
    }

    fn write_at(&self, offset: u64, buf: &[u8]) -> LinuxResult<usize> {
        let mut file = self.inner();
        let original = file.seek(SeekFrom::Current(0))?;
        file.seek(SeekFrom::Start(offset))?;
        let result = file.write(buf);
        file.seek(SeekFrom::Start(original))?;
        Ok(result?)
    }

    fn seek(&self, pos: SeekFrom) -> LinuxResult<u64> {
        Ok(self.inner().seek(pos)?)
    }

    fn truncate(&self, length: u64) -> LinuxResult {
        Ok(self.inner().truncate(length)?)
    }
}

