const CLOCK_BOOTTIME: u32 = 7;
const EVENTFD_MAX: u64 = u64::MAX - 1;

pub struct EventFd {
    counter: Mutex<u64>,
    semaphore: bool,
    nonblocking: AtomicBool,
}

impl EventFd {
    fn new(initval: u64, flags: u32) -> Self {
        Self {
            counter: Mutex::new(initval),
            semaphore: flags & EFD_SEMAPHORE != 0,
            nonblocking: AtomicBool::new(flags & EFD_NONBLOCK != 0),
        }
    }
}

impl FileLike for EventFd {
    fn read(&self, buf: &mut [u8]) -> LinuxResult<usize> {
        if buf.len() < core::mem::size_of::<u64>() {
            return Err(LinuxError::EINVAL);
        }

        loop {
            let mut counter = self.counter.lock();
            if *counter == 0 {
                if self.nonblocking.load(Ordering::Relaxed) {
                    return Err(LinuxError::EAGAIN);
                }
                drop(counter);
                axtask::yield_now();
                continue;
            }

            let value = if self.semaphore {
                *counter -= 1;
                1
            } else {
                let value = *counter;
                *counter = 0;
                value
            };
            buf[..8].copy_from_slice(&value.to_ne_bytes());
            return Ok(8);
        }
    }

    fn write(&self, buf: &[u8]) -> LinuxResult<usize> {
        if buf.len() < core::mem::size_of::<u64>() {
            return Err(LinuxError::EINVAL);
        }

        let mut bytes = [0u8; 8];
        bytes.copy_from_slice(&buf[..8]);
        let value = u64::from_ne_bytes(bytes);
        if value == u64::MAX {
            return Err(LinuxError::EINVAL);
        }

        loop {
            let mut counter = self.counter.lock();
            if *counter > EVENTFD_MAX.saturating_sub(value) {
                if self.nonblocking.load(Ordering::Relaxed) {
                    return Err(LinuxError::EAGAIN);
                }
                drop(counter);
                axtask::yield_now();
                continue;
            }
            *counter += value;
            return Ok(8);
        }
    }

    fn stat(&self) -> LinuxResult<Kstat> {
        Ok(Kstat::default())
    }

    fn into_any(self: Arc<Self>) -> Arc<dyn Any + Send + Sync> {
        self
    }

    fn poll(&self) -> LinuxResult<PollState> {
        let counter = *self.counter.lock();
        Ok(PollState {
            readable: counter > 0,
            writable: counter < EVENTFD_MAX,
        })
    }

    fn set_nonblocking(&self, nonblocking: bool) -> LinuxResult {
        self.nonblocking.store(nonblocking, Ordering::Relaxed);
        Ok(())
    }
}

pub fn sys_eventfd2(initval: u32, flags: u32) -> LinuxResult<isize> {
    debug!("sys_eventfd2 <= initval: {initval}, flags: {flags:#x}");
    if flags & !(EFD_CLOEXEC | EFD_NONBLOCK | EFD_SEMAPHORE) != 0 {
        return Err(LinuxError::EINVAL);
    }
    let fd = EventFd::new(initval as u64, flags).add_to_fd_table()?;
    Ok(fd as isize)
}

#[derive(Clone, Copy)]
struct TimerState {
    clock_id: __kernel_clockid_t,
    spec: itimerspec,
    set_time_ns: u64,
    expirations: u64,
    active: bool,
    abstime: bool,
}

impl TimerState {
    fn new(clock_id: __kernel_clockid_t) -> Self {
        Self {
            clock_id,
            spec: zero_itimerspec(),
            set_time_ns: 0,
            expirations: 0,
            active: false,
            abstime: false,
        }
    }

    fn now_ns(&self) -> u64 {
        match self.clock_id as u32 {
            CLOCK_REALTIME => time_value_to_ns(wall_time()),
            CLOCK_MONOTONIC | CLOCK_BOOTTIME => time_value_to_ns(monotonic_time()),
            _ => time_value_to_ns(monotonic_time()),
        }
    }

    fn set_timer(&mut self, spec: itimerspec, flags: u32) -> LinuxResult<itimerspec> {
        validate_itimerspec(spec)?;
        if flags & !(TFD_TIMER_ABSTIME | TFD_TIMER_CANCEL_ON_SET) != 0 {
            return Err(LinuxError::EINVAL);
        }

        let old = self.current_spec();
        self.spec = spec;
        self.abstime = flags & TFD_TIMER_ABSTIME != 0;
        self.active = timespec_to_ns(spec.it_value)? != 0;
        self.expirations = 0;
        self.set_time_ns = self.now_ns();
        Ok(old)
    }

    fn current_spec(&self) -> itimerspec {
        if !self.active {
            return itimerspec {
                it_interval: self.spec.it_interval,
                it_value: zero_timespec(),
            };
        }

        let value_ns = timespec_to_ns(self.spec.it_value).unwrap_or(0);
        let expire_ns = if self.abstime {
            value_ns
        } else {
            self.set_time_ns.saturating_add(value_ns)
        };
        let remaining = expire_ns.saturating_sub(self.now_ns());
        itimerspec {
            it_interval: self.spec.it_interval,
            it_value: ns_to_timespec(remaining),
        }
    }

    fn check_expiration(&mut self) -> LinuxResult<u64> {
        if !self.active {
            return Ok(0);
        }

        let value_ns = timespec_to_ns(self.spec.it_value)?;
        if value_ns == 0 {
            self.active = false;
            return Ok(0);
        }

        let expire_ns = if self.abstime {
            value_ns
        } else {
            self.set_time_ns.saturating_add(value_ns)
        };
        let now = self.now_ns();
        if now < expire_ns {
            return Ok(0);
        }

        let interval_ns = timespec_to_ns(self.spec.it_interval)?;
        if interval_ns == 0 {
            self.active = false;
            self.expirations = self.expirations.saturating_add(1);
            Ok(self.expirations)
        } else {
            let periods = now.saturating_sub(expire_ns) / interval_ns + 1;
            self.expirations = self.expirations.saturating_add(periods);
            if self.abstime {
                self.spec.it_value =
                    ns_to_timespec(expire_ns.saturating_add(periods * interval_ns));
            } else {
                self.set_time_ns = expire_ns.saturating_add(periods * interval_ns);
            }
            Ok(self.expirations)
        }
    }
}

