/// Convert open flags to [`OpenOptions`].
fn flags_to_options(flags: c_int, _mode: __kernel_mode_t) -> OpenOptions {
    let flags = flags as u32;
    let mut options = OpenOptions::new();
    match flags & 0b11 {
        O_RDONLY => options.read(true),
        O_WRONLY => options.write(true),
        _ => {
            options.read(true);
            options.write(true);
        }
    };
    if flags & O_APPEND != 0 {
        options.append(true);
    }
    if flags & O_TRUNC != 0 {
        options.truncate(true);
    }
    if flags & O_CREAT != 0 {
        options.create(true);
    }
    if flags & O_EXEC != 0 {
        //options.create_new(true);
        options.execute(true);
    }
    if flags & O_DIRECTORY != 0 {
        options.directory(true);
    }
    options
}

/// Open or create a file.
/// fd: file descriptor
/// filename: file path to be opened or created
/// flags: open flags
/// mode: see man 7 inode
/// return new file descriptor if succeed, or return -1.
pub fn sys_openat(
    dirfd: c_int,
    path: UserConstPtr<c_char>,
    flags: i32,
    mode: __kernel_mode_t,
) -> LinuxResult<isize> {
    let path = path.get_as_str()?;
    let opts = flags_to_options(flags, mode);
    debug!("sys_openat <= {} {} {:?}", dirfd, path, opts);

    let dir = if path.starts_with('/') || dirfd == AT_FDCWD {
        None
    } else {
        Some(Directory::from_fd(dirfd)?)
    };
    let real_path = handle_file_path(dirfd, path)?;
    let is_dir = axfs::api::metadata(real_path.as_str())
        .map(|metadata| metadata.is_dir())
        .unwrap_or(false);

    if !opts.has_directory() && !is_dir {
        match dir.as_ref().map_or_else(
            || axfs::fops::File::open(path, &opts),
            |dir| dir.inner().open_file_at(path, &opts),
        ) {
            Err(AxError::IsADirectory) => {}
            r => {
                let fd = File::new(r?, real_path.to_string()).add_to_fd_table()?;
                return Ok(fd as _);
            }
        }
    }

    let fd = Directory::new(
        dir.map_or_else(
            || axfs::fops::Directory::open_dir(path, &opts),
            |dir| dir.inner().open_dir_at(path, &opts),
        )?,
        real_path.to_string(),
    )
    .add_to_fd_table()?;
    Ok(fd as _)
}

/// Open a file by `filename` and insert it into the file descriptor table.
///
/// Return its index in the file table (`fd`). Return `EMFILE` if it already
/// has the maximum number of files open.
pub fn sys_open(
    path: UserConstPtr<c_char>,
    flags: i32,
    mode: __kernel_mode_t,
) -> LinuxResult<isize> {
    sys_openat(AT_FDCWD as _, path, flags, mode)
}

pub fn sys_close(fd: c_int) -> LinuxResult<isize> {
    debug!("sys_close <= {}", fd);
    close_file_like(fd)?;
    Ok(0)
}

pub fn sys_close_range(first: u32, last: u32, flags: u32) -> LinuxResult<isize> {
    debug!("sys_close_range <= first: {first}, last: {last}, flags: {flags:#x}");
    if first > last {
        return Err(LinuxError::EINVAL);
    }
    if flags & !(CLOSE_RANGE_UNSHARE | CLOSE_RANGE_CLOEXEC) != 0 {
        return Err(LinuxError::EINVAL);
    }

    // Descriptor flags are not tracked yet. Accepting CLOEXEC keeps modern
    // libc probes moving while preserving the currently open descriptors.
    if flags & CLOSE_RANGE_CLOEXEC != 0 {
        return Ok(0);
    }

    let end = core::cmp::min(last as usize, AX_FILE_LIMIT - 1);
    let mut fd_table = FD_TABLE.write();
    for fd in first as usize..=end {
        let _ = fd_table.remove(fd);
    }
    Ok(0)
}

fn dup_fd_from(old_fd: c_int, min_fd: usize) -> LinuxResult<isize> {
    let f = get_file_like(old_fd)?;
    if min_fd >= AX_FILE_LIMIT {
        return Err(LinuxError::EINVAL);
    }

    let mut fd_table = FD_TABLE.write();
    for new_fd in min_fd..AX_FILE_LIMIT {
        if fd_table.get(new_fd).is_none() {
            fd_table.add_at(new_fd, f).map_err(|_| LinuxError::EMFILE)?;
            return Ok(new_fd as _);
        }
    }
    Err(LinuxError::EMFILE)
}

fn dup_fd(old_fd: c_int) -> LinuxResult<isize> {
    dup_fd_from(old_fd, 0)
}

pub fn sys_dup(old_fd: c_int) -> LinuxResult<isize> {
    debug!("sys_dup <= {}", old_fd);
    dup_fd(old_fd)
}

pub fn sys_dup2(old_fd: c_int, new_fd: c_int) -> LinuxResult<isize> {
    debug!("sys_dup2 <= old_fd: {}, new_fd: {}", old_fd, new_fd);
    if new_fd < 0 || new_fd as usize >= AX_FILE_LIMIT {
        return Err(LinuxError::EBADF);
    }

    let mut fd_table = FD_TABLE.write();
    let f = fd_table
        .get(old_fd as _)
        .cloned()
        .ok_or(LinuxError::EBADF)?;

    if old_fd != new_fd {
        fd_table.remove(new_fd as _);
        fd_table
            .add_at(new_fd as _, f)
            .unwrap_or_else(|_| panic!("new_fd should be valid"));
    }

    Ok(new_fd as _)
}

pub fn sys_dup3(old_fd: c_int, new_fd: c_int, flags: c_int) -> LinuxResult<isize> {
    debug!(
        "sys_dup3 <= old_fd: {}, new_fd: {}, flags: {:#x}",
        old_fd, new_fd, flags
    );
    if old_fd == new_fd {
        return Err(LinuxError::EINVAL);
    }
    if flags & !(O_CLOEXEC as c_int) != 0 {
        return Err(LinuxError::EINVAL);
    }
    sys_dup2(old_fd, new_fd)
}

pub fn sys_fcntl(fd: c_int, cmd: c_int, arg: usize) -> LinuxResult<isize> {
    debug!("sys_fcntl <= fd: {} cmd: {} arg: {}", fd, cmd, arg);

    match cmd as u32 {
        F_DUPFD => dup_fd_from(fd, arg),
        F_DUPFD_CLOEXEC => {
            // Descriptor flags are not yet tracked, but allocation semantics
            // and the requested lower bound still match Linux.
            dup_fd_from(fd, arg)
        }
        F_GETFD => Ok(get_file_like(fd)?.descriptor_flags()? as isize),
        F_GETFL => Ok(get_file_like(fd)?.status_flags()? as isize),
        F_SETFD => {
            get_file_like(fd)?;
            Ok(0)
        }
        F_SETFL => {
            if fd == 0 || fd == 1 || fd == 2 {
                return Ok(0);
            }
            get_file_like(fd)?.set_nonblocking(arg & (O_NONBLOCK as usize) > 0)?;
            Ok(0)
        }
        F_ADD_SEALS => {
            get_file_like(fd)?.add_seals(arg as u32)?;
            Ok(0)
        }
        F_GET_SEALS => Ok(get_file_like(fd)?.get_seals()? as isize),
        _ => {
            warn!("unsupported fcntl parameters: cmd: {}", cmd);
            Ok(0)
        }
    }
}

//! Trap handling.

use linkme::distributed_slice as def_trap_handler;
use memory_addr::VirtAddr;
use page_table_entry::MappingFlags;

pub use linkme::distributed_slice as register_trap_handler;

use crate::arch::TrapFrame;

/// A slice of IRQ handler functions.
#[def_trap_handler]
pub static IRQ: [fn(usize) -> bool];

/// A slice of page fault handler functions.
#[def_trap_handler]
pub static PAGE_FAULT: [fn(VirtAddr, MappingFlags, bool) -> bool];

/// A slice of syscall handler functions.
#[cfg(feature = "uspace")]
#[def_trap_handler]
pub static SYSCALL: [fn(&mut TrapFrame, usize) -> isize];

/// A slice of callbacks to be invoked after a trap.
#[linkme::distributed_slice]
pub static POST_TRAP: [fn(&mut TrapFrame, bool)];

#[allow(unused_macros)]
macro_rules! handle_trap {
    ($trap:ident, $($args:tt)*) => {{
        let mut iter = $crate::trap::$trap.iter();
        if let Some(func) = iter.next() {
            if iter.next().is_some() {
                warn!("Multiple handlers for trap {} are not currently supported", stringify!($trap));
            }
            func($($args)*)
        } else {
            warn!("No registered handler for trap {}", stringify!($trap));
            false
        }
    }}
}

#[unsafe(no_mangle)]
pub(crate) fn post_trap_callback(tf: &mut TrapFrame, from_user: bool) {
    for cb in crate::trap::POST_TRAP.iter() {
        cb(tf, from_user);
    }
}

/// Call the external syscall handler.
#[cfg(feature = "uspace")]
pub(crate) fn handle_syscall(tf: &mut TrapFrame, syscall_num: usize) -> isize {
    SYSCALL[0](tf, syscall_num)
}

//! [ArceOS](https://github.com/arceos-org/arceos) namespaces module.
//!
//! Namespaces are used to control system resource sharing between threads. This
//! module provides a unified interface to access system resources in different
//! scenarios.
//!
//! For a unikernel, there is only one global namespace, so all threads share
//! the same system resources, such as virtual address space, working directory,
//! and file descriptors, etc.
//!
//! For a monolithic kernel, each process corresponds to a namespace, all
//! threads in the same process share the same system resources. Different
//! processes have different namespaces and isolated resources.
//!
//! For further container support, some global system resources can also be
//! grouped into a namespace.
//!
//! See the examples of [`def_resource!`] for more usage.

#![cfg_attr(not(test), no_std)]

extern crate alloc;

use alloc::sync::Arc;
use core::{alloc::Layout, fmt, ops::Deref};

use lazyinit::LazyInit;

unsafe extern "C" {
    fn __start_axns_resource();
    fn __stop_axns_resource();
}

/// A namespace that contains all user-defined resources.
///
/// There are two types of namespaces:
///
/// - Global namespace: this namespace is globally unique and all threads share
///   the resources in it. Resources are statically collected into the
///   `axns_resource` section, and the global namespace is constructed by the base
///   address of the section ([`AxNamespace::global`]).
/// - Thread-local namespace: this namespace is per-thread, each thread should
///   call [`AxNamespace::new_thread_local()`] to allocate a memory area as its
///   namespace. Layout of resources in global and thread-local namespaces is
///   consistent. Each namespace has its own resources, which may be unique or
///   shared between threads by the [`Arc`] wrapper.
pub struct AxNamespace {
    base: usize,
    alloc: bool,
}

impl AxNamespace {
    /// Returns the base address of the namespace, which points to the start of
    /// all resources.
    pub const fn base(&self) -> *mut u8 {
        self.base as *mut u8
    }

    /// Returns the size of the namespace (size of all resources).
    pub fn size(&self) -> usize {
        Self::section_size()
    }

    /// Returns the size of the `axns_resource` section.
    fn section_size() -> usize {
        __stop_axns_resource as usize - __start_axns_resource as usize
    }

    /// Returns the global namespace.
    pub fn global() -> Self {
        Self {
            base: __start_axns_resource as usize,
            alloc: false,
        }
    }

    /// Constructs a new thread-local namespace.
    ///
    /// Each thread can have its own namespace instead of the global one, to
    /// isolate resources between threads.
    ///
    /// This function allocates a memory area to store the thread-local resources,
    /// and copies from the global namespace as the initial value.
    #[cfg(feature = "thread-local")]
    pub fn new_thread_local() -> Self {
        let size = Self::section_size();
        let base = if size == 0 {
            core::ptr::null_mut()
        } else {
            let layout = Layout::from_size_align(size, 64).unwrap();
            let dst = unsafe { alloc::alloc::alloc(layout) };
            let src = __start_axns_resource as *const u8;
            unsafe { core::ptr::copy_nonoverlapping(src, dst, size) };
            dst
        } as usize;
        Self { base, alloc: true }
    }
}

