const SCHED_FLAG_ALL: u64 = 0x7f;
const SCHED_ATTR_MIN_SIZE: usize = 48;

static SCHED_POLICY: AtomicU32 = AtomicU32::new(SCHED_NORMAL);
static SCHED_PRIORITY: AtomicI32 = AtomicI32::new(0);
static SCHED_FLAGS: AtomicU64 = AtomicU64::new(0);
static SCHED_RUNTIME: AtomicU64 = AtomicU64::new(0);
static SCHED_DEADLINE_VALUE: AtomicU64 = AtomicU64::new(0);
static SCHED_PERIOD: AtomicU64 = AtomicU64::new(0);

#[repr(C)]
#[derive(Clone, Copy, Default)]
pub struct SchedParam {
    sched_priority: i32,
}

#[repr(C)]
#[derive(Clone, Copy, Default)]
struct SchedAttr {
    size: u32,
    sched_policy: u32,
    sched_flags: u64,
    sched_nice: i32,
    sched_priority: u32,
    sched_runtime: u64,
    sched_deadline: u64,
    sched_period: u64,
    sched_util_min: u32,
    sched_util_max: u32,
}

fn check_sched_pid(pid: i32) -> LinuxResult {
    if pid < 0 {
        return Err(LinuxError::EINVAL);
    }
    let current_pid = current().task_ext().thread.process().pid() as i32;
    if pid != 0 && pid != current_pid {
        return Err(LinuxError::ESRCH);
    }
    Ok(())
}

fn normalize_sched_policy(policy: i32) -> LinuxResult<u32> {
    let policy = (policy as u32) & !SCHED_RESET_ON_FORK;
    match policy {
        SCHED_NORMAL | SCHED_FIFO | SCHED_RR | SCHED_BATCH | SCHED_IDLE | SCHED_DEADLINE => {
            Ok(policy)
        }
        _ => Err(LinuxError::EINVAL),
    }
}

fn validate_sched_priority(policy: u32, priority: i32) -> LinuxResult {
    match policy {
        SCHED_FIFO | SCHED_RR => {
            if !(1..=99).contains(&priority) {
                return Err(LinuxError::EINVAL);
            }
        }
        SCHED_DEADLINE => {
            if priority != 0 {
                return Err(LinuxError::EINVAL);
            }
        }
        _ => {
            if priority != 0 {
                return Err(LinuxError::EINVAL);
            }
        }
    }
    Ok(())
}

fn read_sched_attr(attr: UserConstPtr<u8>) -> LinuxResult<SchedAttr> {
    let size = *UserConstPtr::<u32>::from(attr.address().as_usize()).get_as_ref()? as usize;
    if size < SCHED_ATTR_MIN_SIZE {
        return Err(LinuxError::EINVAL);
    }

    let mut value = SchedAttr {
        size: size_of::<SchedAttr>() as u32,
        ..SchedAttr::default()
    };
    let copy_len = core::cmp::min(size, size_of::<SchedAttr>());
    let src = attr.get_as_slice(copy_len)?;
    let dst = unsafe {
        slice::from_raw_parts_mut(
            (&mut value as *mut SchedAttr).cast::<u8>(),
            size_of::<SchedAttr>(),
        )
    };
    dst[..copy_len].copy_from_slice(src);
    Ok(value)
}

pub fn sys_sched_yield() -> LinuxResult<isize> {
    axtask::yield_now();
    Ok(0)
}

pub fn sys_sched_getaffinity(
    pid: i32,
    cpusetsize: usize,
    mask: UserPtr<usize>,
) -> LinuxResult<isize> {
    check_sched_pid(pid)?;
    if cpusetsize < size_of::<usize>() {
        return Err(LinuxError::EINVAL);
    }
    let slots = cpusetsize / size_of::<usize>();
    let mask = mask.get_as_mut_slice(slots)?;
    mask.fill(0);
    mask[0] = 1;
    Ok(cpusetsize as _)
}

pub fn sys_sched_setaffinity(
    pid: i32,
    cpusetsize: usize,
    mask: UserConstPtr<usize>,
) -> LinuxResult<isize> {
    check_sched_pid(pid)?;
    if cpusetsize < size_of::<usize>() {
        return Err(LinuxError::EINVAL);
    }
    if *mask.get_as_ref()? & 1 == 0 {
        return Err(LinuxError::EINVAL);
    }
    Ok(0)
}

pub fn sys_sched_getscheduler(pid: i32) -> LinuxResult<isize> {
    check_sched_pid(pid)?;
    Ok(SCHED_POLICY.load(Ordering::Relaxed) as _)
}

pub fn sys_sched_getparam(pid: i32, param: UserPtr<SchedParam>) -> LinuxResult<isize> {
    check_sched_pid(pid)?;
    *param.get_as_mut()? = SchedParam {
        sched_priority: SCHED_PRIORITY.load(Ordering::Relaxed),
    };
    Ok(0)
}

pub fn sys_sched_setparam(pid: i32, param: UserPtr<SchedParam>) -> LinuxResult<isize> {
    check_sched_pid(pid)?;
    let priority = param.get_as_mut()?.sched_priority;
    validate_sched_priority(SCHED_POLICY.load(Ordering::Relaxed), priority)?;
    SCHED_PRIORITY.store(priority, Ordering::Relaxed);
    Ok(0)
}

pub fn sys_sched_setscheduler(
    pid: i32,
    policy: i32,
    param: UserPtr<SchedParam>,
) -> LinuxResult<isize> {
    check_sched_pid(pid)?;
    let policy = normalize_sched_policy(policy)?;
    let priority = param.get_as_mut()?.sched_priority;
    validate_sched_priority(policy, priority)?;
    SCHED_POLICY.store(policy, Ordering::Relaxed);
    SCHED_PRIORITY.store(priority, Ordering::Relaxed);
    Ok(0)
}

pub fn sys_sched_get_priority_max(policy: i32) -> LinuxResult<isize> {
    match normalize_sched_policy(policy)? {
        SCHED_FIFO | SCHED_RR => Ok(99),
        _ => Ok(0),
    }
}

pub fn sys_sched_get_priority_min(policy: i32) -> LinuxResult<isize> {
    match normalize_sched_policy(policy)? {
        SCHED_FIFO | SCHED_RR => Ok(1),
        _ => Ok(0),
    }
}

pub fn sys_sched_rr_get_interval(pid: i32, interval: UserPtr<timespec>) -> LinuxResult<isize> {
    check_sched_pid(pid)?;
    *interval.get_as_mut()? = timespec {
        tv_sec: 0,
        tv_nsec: if SCHED_POLICY.load(Ordering::Relaxed) == SCHED_FIFO {
