use core::ffi::c_int;

use axerrno::{LinuxError, LinuxResult};
use axhal::time::{monotonic_time, monotonic_time_nanos, nanos_to_ticks, wall_time};
use linux_raw_sys::general::{
    __kernel_clockid_t, __kernel_old_timeval, CLOCK_MONOTONIC, CLOCK_REALTIME, RUSAGE_CHILDREN,
    RUSAGE_SELF, RUSAGE_THREAD, rusage, timespec, timeval,
};
use starry_core::task::time_stat_output;

use crate::{
    ptr::{UserConstPtr, UserPtr},
    time::TimeValueLike,
};

const CLOCK_PROCESS_CPUTIME_ID: u32 = 2;
const CLOCK_THREAD_CPUTIME_ID: u32 = 3;
const CLOCK_MONOTONIC_RAW: u32 = 4;
const CLOCK_REALTIME_COARSE: u32 = 5;
const CLOCK_MONOTONIC_COARSE: u32 = 6;
const CLOCK_BOOTTIME: u32 = 7;

const ITIMER_REAL: c_int = 0;
const ITIMER_VIRTUAL: c_int = 1;
const ITIMER_PROF: c_int = 2;

#[repr(C)]
#[derive(Clone, Copy)]
pub struct Itimerval {
    it_interval: timeval,
    it_value: timeval,
}

pub fn sys_clock_gettime(
    clock_id: __kernel_clockid_t,
    ts: UserPtr<timespec>,
) -> LinuxResult<isize> {
    let now = match clock_id as u32 {
        CLOCK_REALTIME | CLOCK_REALTIME_COARSE => wall_time(),
        CLOCK_MONOTONIC
        | CLOCK_MONOTONIC_RAW
        | CLOCK_MONOTONIC_COARSE
        | CLOCK_BOOTTIME
        | CLOCK_PROCESS_CPUTIME_ID
        | CLOCK_THREAD_CPUTIME_ID => monotonic_time(),
        _ => {
            warn!(
                "Called sys_clock_gettime for unsupported clock {}",
                clock_id
            );
            return Err(LinuxError::EINVAL);
        }
    };
    *ts.get_as_mut()? = timespec::from_time_value(now);
    Ok(0)
}

pub fn sys_clock_getres(clock_id: __kernel_clockid_t, ts: UserPtr<timespec>) -> LinuxResult<isize> {
    match clock_id as u32 {
        CLOCK_REALTIME
        | CLOCK_REALTIME_COARSE
        | CLOCK_MONOTONIC
        | CLOCK_MONOTONIC_RAW
        | CLOCK_MONOTONIC_COARSE
        | CLOCK_BOOTTIME
        | CLOCK_PROCESS_CPUTIME_ID
        | CLOCK_THREAD_CPUTIME_ID => {}
        _ => return Err(LinuxError::EINVAL),
    }

    if !ts.is_null() {
        *ts.get_as_mut()? = timespec {
            tv_sec: 0,
            tv_nsec: 1,
        };
    }
    Ok(0)
}

pub fn sys_gettimeofday(ts: UserPtr<timeval>) -> LinuxResult<isize> {
    *ts.get_as_mut()? = timeval::from_time_value(wall_time());
    Ok(0)
}

pub fn sys_getitimer(which: c_int, curr_value: UserPtr<Itimerval>) -> LinuxResult<isize> {
    validate_itimer_kind(which)?;
    *curr_value.get_as_mut()? = zero_itimerval();
    Ok(0)
}

pub fn sys_setitimer(
    which: c_int,
    new_value: UserConstPtr<Itimerval>,
    old_value: UserPtr<Itimerval>,
) -> LinuxResult<isize> {
    validate_itimer_kind(which)?;
    let new_value = *new_value.get_as_ref()?;
    validate_itimerval(new_value)?;
    if !old_value.is_null() {
        *old_value.get_as_mut()? = zero_itimerval();
    }
    if reject_active_itimer(new_value) {
        return Err(LinuxError::ENOSYS);
    }
    Ok(0)
}

#[repr(C)]
pub struct Tms {
    /// user time
    tms_utime: usize,
    /// system time
    tms_stime: usize,
    /// user time of children
    tms_cutime: usize,
    /// system time of children
    tms_cstime: usize,
}

pub fn sys_times(tms: UserPtr<Tms>) -> LinuxResult<isize> {
    let (_, utime_us, _, stime_us) = time_stat_output();
    *tms.get_as_mut()? = Tms {
        tms_utime: utime_us,
        tms_stime: stime_us,
        tms_cutime: utime_us,
        tms_cstime: stime_us,
    };
    Ok(nanos_to_ticks(monotonic_time_nanos()) as _)
}

fn timeval_from_micros(us: usize) -> __kernel_old_timeval {
    __kernel_old_timeval {
        tv_sec: (us / 1_000_000) as _,
        tv_usec: (us % 1_000_000) as _,
    }
}

pub fn sys_getrusage(who: i32, usage: UserPtr<rusage>) -> LinuxResult<isize> {
    if who != RUSAGE_SELF as i32 && who != RUSAGE_THREAD as i32 && who != RUSAGE_CHILDREN {
        return Err(LinuxError::EINVAL);
    }

    let (_, utime_us, _, stime_us) = time_stat_output();
    let mut result = rusage {
        ru_utime: timeval_from_micros(0),
        ru_stime: timeval_from_micros(0),
        ru_maxrss: 0,
        ru_ixrss: 0,
        ru_idrss: 0,
        ru_isrss: 0,
        ru_minflt: 0,
        ru_majflt: 0,
        ru_nswap: 0,
        ru_inblock: 0,
        ru_oublock: 0,
        ru_msgsnd: 0,
        ru_msgrcv: 0,
        ru_nsignals: 0,
        ru_nvcsw: 0,
        ru_nivcsw: 0,
    };
    if who != RUSAGE_CHILDREN {
        result.ru_utime = timeval_from_micros(utime_us);
        result.ru_stime = timeval_from_micros(stime_us);
    }
    *usage.get_as_mut()? = result;
    Ok(0)
}

fn validate_itimer_kind(which: c_int) -> LinuxResult {
    match which {
        ITIMER_REAL | ITIMER_VIRTUAL | ITIMER_PROF => Ok(()),
        _ => Err(LinuxError::EINVAL),
    }
}

fn validate_itimerval(value: Itimerval) -> LinuxResult {
    validate_timeval(value.it_interval)?;
    validate_timeval(value.it_value)
}

fn reject_active_itimer(value: Itimerval) -> bool {
    cfg!(target_arch = "riscv64") && !itimerval_is_zero(value)
}

fn itimerval_is_zero(value: Itimerval) -> bool {
    value.it_interval.tv_sec == 0
        && value.it_interval.tv_usec == 0
        && value.it_value.tv_sec == 0
        && value.it_value.tv_usec == 0
}

fn validate_timeval(value: timeval) -> LinuxResult {
    if value.tv_sec < 0 || value.tv_usec < 0 || value.tv_usec >= 1_000_000 {
        return Err(LinuxError::EINVAL);
    }
    Ok(())
}

fn zero_itimerval() -> Itimerval {
    Itimerval {
        it_interval: timeval {
            tv_sec: 0,
            tv_usec: 0,
        },
        it_value: timeval {
            tv_sec: 0,
            tv_usec: 0,
        },
    }
}

