const UNIX_BUFFER_SIZE: usize = 64 * 1024;

pub enum Socket {
    Udp(Mutex<UdpSocket>),
    Tcp(Mutex<TcpSocket>),
    Unix(UnixSocket),
}

pub struct UnixSocket {
    incoming: Arc<Mutex<VecDeque<u8>>>,
    outgoing: Arc<Mutex<VecDeque<u8>>>,
    nonblocking: AtomicBool,
    cloexec: AtomicBool,
}

impl UnixSocket {
    pub fn pair(nonblocking: bool, cloexec: bool) -> (Self, Self) {
        let left_to_right = Arc::new(Mutex::new(VecDeque::with_capacity(UNIX_BUFFER_SIZE)));
        let right_to_left = Arc::new(Mutex::new(VecDeque::with_capacity(UNIX_BUFFER_SIZE)));
        (
            Self {
                incoming: right_to_left.clone(),
                outgoing: left_to_right.clone(),
                nonblocking: AtomicBool::new(nonblocking),
                cloexec: AtomicBool::new(cloexec),
            },
            Self {
                incoming: left_to_right,
                outgoing: right_to_left,
                nonblocking: AtomicBool::new(nonblocking),
                cloexec: AtomicBool::new(cloexec),
            },
        )
    }

    fn recv(&self, buf: &mut [u8]) -> LinuxResult<usize> {
        if buf.is_empty() {
            return Ok(0);
        }
        loop {
            let mut incoming = self.incoming.lock();
            let read_size = incoming.len().min(buf.len());
            if read_size > 0 {
                for slot in buf.iter_mut().take(read_size) {
                    *slot = incoming.pop_front().unwrap_or(0);
                }
                return Ok(read_size);
            }
            if Arc::strong_count(&self.incoming) == 1 {
                return Ok(0);
            }
            if self.nonblocking.load(Ordering::Relaxed) {
                return Err(LinuxError::EAGAIN);
            }
            drop(incoming);
            axtask::yield_now();
        }
    }

    fn send(&self, buf: &[u8]) -> LinuxResult<usize> {
        if Arc::strong_count(&self.outgoing) == 1 {
            return Err(LinuxError::EPIPE);
        }
        if buf.is_empty() {
            return Ok(0);
        }
        let mut written = 0usize;
        loop {
            let mut outgoing = self.outgoing.lock();
            let available = UNIX_BUFFER_SIZE.saturating_sub(outgoing.len());
            if available > 0 {
                let write_size = available.min(buf.len() - written);
                outgoing.extend(buf[written..written + write_size].iter().copied());
                written += write_size;
                if written == buf.len() {
                    return Ok(written);
                }
            }
            if self.nonblocking.load(Ordering::Relaxed) {
                return if written > 0 {
                    Ok(written)
                } else {
                    Err(LinuxError::EAGAIN)
                };
            }
            drop(outgoing);
            axtask::yield_now();
        }
    }

    fn poll(&self) -> PollState {
        PollState {
            readable: !self.incoming.lock().is_empty() || Arc::strong_count(&self.incoming) == 1,
            writable: self.outgoing.lock().len() < UNIX_BUFFER_SIZE
                && Arc::strong_count(&self.outgoing) > 1,
        }
    }

    fn set_nonblocking(&self, nonblocking: bool) {
        self.nonblocking.store(nonblocking, Ordering::Relaxed);
    }

    fn descriptor_flags(&self) -> u32 {
        if self.cloexec.load(Ordering::Relaxed) {
            FD_CLOEXEC
        } else {
            0
        }
    }

    fn status_flags(&self) -> u32 {
        if self.nonblocking.load(Ordering::Relaxed) {
            O_NONBLOCK
        } else {
            0
        }
    }
}

