const GETRANDOM_ALLOWED_FLAGS: u32 = linux_raw_sys::general::GRND_NONBLOCK
    | linux_raw_sys::general::GRND_RANDOM
    | linux_raw_sys::general::GRND_INSECURE;
static RANDOM_COUNTER: AtomicU64 = AtomicU64::new(0x6a09_e667_f3bc_c909);

fn random_word() -> u64 {
    let mut value = RANDOM_COUNTER.fetch_add(0x9e37_79b9_7f4a_7c15, Ordering::Relaxed)
        ^ axhal::time::monotonic_time_nanos();
    value = (value ^ (value >> 30)).wrapping_mul(0xbf58_476d_1ce4_e5b9);
    value = (value ^ (value >> 27)).wrapping_mul(0x94d0_49bb_1331_11eb);
    value ^ (value >> 31)
}

#[repr(C)]
#[derive(Clone, Copy)]
pub struct RLimit {
    rlim_cur: u64,
    rlim_max: u64,
}

const RLIMIT_STACK: u32 = 3;
const RLIMIT_NOFILE: u32 = 7;
const RLIMIT_MAX: u32 = 15;

fn resource_limit(resource: u32) -> LinuxResult<RLimit> {
    if resource > RLIMIT_MAX {
        return Err(LinuxError::EINVAL);
    }

    let limit = match resource {
        RLIMIT_STACK => axconfig::TASK_STACK_SIZE as u64,
        RLIMIT_NOFILE => AX_FILE_LIMIT as u64,
        _ => u64::MAX,
    };
    Ok(RLimit {
        rlim_cur: limit,
        rlim_max: limit,
    })
}

pub fn sys_getrlimit(resource: u32, old_limit: UserPtr<RLimit>) -> LinuxResult<isize> {
    if let Some(old_limit) = nullable!(old_limit.get_as_mut())? {
        *old_limit = resource_limit(resource)?;
    } else {
        resource_limit(resource)?;
    }
    Ok(0)
}

pub fn sys_prlimit64(
    pid: i32,
    resource: u32,
    new_limit: UserConstPtr<RLimit>,
    old_limit: UserPtr<RLimit>,
) -> LinuxResult<isize> {
    let current_pid = axtask::current().task_ext().thread.process().pid() as i32;
    if pid != 0 && pid != current_pid {
        return Err(LinuxError::ESRCH);
    }
    if let Some(new_limit) = nullable!(new_limit.get_as_ref())? {
        if new_limit.rlim_cur > new_limit.rlim_max {
            return Err(LinuxError::EINVAL);
        }
    }
    sys_getrlimit(resource, old_limit)
}

