pub fn sys_sysinfo(info: UserPtr<SysInfo>) -> LinuxResult<isize> {
    const TOTAL_RAM: u64 = 1024 * 1024 * 1024;
    const FREE_RAM: u64 = 768 * 1024 * 1024;

    *info.get_as_mut()? = SysInfo {
        uptime: axhal::time::monotonic_time().as_secs() as i64,
        totalram: TOTAL_RAM,
        freeram: FREE_RAM,
        procs: 1,
        mem_unit: 1,
        ..SysInfo::default()
    };
    Ok(0)
}

pub fn sys_syslog(action: i32, buf: UserPtr<u8>, len: usize) -> LinuxResult<isize> {
    const SYSLOG_ACTION_READ_ALL: i32 = 3;
    const SYSLOG_ACTION_SIZE_UNREAD: i32 = 9;
    const SYSLOG_ACTION_SIZE_BUFFER: i32 = 10;

    match action {
        SYSLOG_ACTION_READ_ALL => {
            if len != 0 {
                buf.get_as_mut_slice(len)?[0] = 0;
            }
            Ok(0)
        }
        SYSLOG_ACTION_SIZE_UNREAD => Ok(0),
        SYSLOG_ACTION_SIZE_BUFFER => Ok(4096),
        0..=8 => Ok(0),
        _ => Err(LinuxError::EINVAL),
    }
}

pub fn sys_membarrier(cmd: c_int, flags: c_int, _cpu_id: c_int) -> LinuxResult<isize> {
    const MEMBARRIER_CMD_QUERY: c_int = 0;
    const MEMBARRIER_CMD_GLOBAL: c_int = 1;
    const MEMBARRIER_CMD_GLOBAL_EXPEDITED: c_int = 2;
    const MEMBARRIER_CMD_REGISTER_GLOBAL_EXPEDITED: c_int = 4;
    const MEMBARRIER_CMD_PRIVATE_EXPEDITED: c_int = 8;
    const MEMBARRIER_CMD_REGISTER_PRIVATE_EXPEDITED: c_int = 16;
    const MEMBARRIER_CMD_PRIVATE_EXPEDITED_SYNC_CORE: c_int = 32;
    const MEMBARRIER_CMD_REGISTER_PRIVATE_EXPEDITED_SYNC_CORE: c_int = 64;

    const SUPPORTED: c_int = MEMBARRIER_CMD_GLOBAL
        | MEMBARRIER_CMD_GLOBAL_EXPEDITED
        | MEMBARRIER_CMD_REGISTER_GLOBAL_EXPEDITED
        | MEMBARRIER_CMD_PRIVATE_EXPEDITED
        | MEMBARRIER_CMD_REGISTER_PRIVATE_EXPEDITED
        | MEMBARRIER_CMD_PRIVATE_EXPEDITED_SYNC_CORE
        | MEMBARRIER_CMD_REGISTER_PRIVATE_EXPEDITED_SYNC_CORE;

    if flags != 0 {
        return Err(LinuxError::EINVAL);
    }

    match cmd {
        MEMBARRIER_CMD_QUERY => Ok(SUPPORTED as _),
        MEMBARRIER_CMD_GLOBAL
        | MEMBARRIER_CMD_GLOBAL_EXPEDITED
        | MEMBARRIER_CMD_REGISTER_GLOBAL_EXPEDITED
        | MEMBARRIER_CMD_PRIVATE_EXPEDITED
        | MEMBARRIER_CMD_REGISTER_PRIVATE_EXPEDITED
        | MEMBARRIER_CMD_PRIVATE_EXPEDITED_SYNC_CORE
        | MEMBARRIER_CMD_REGISTER_PRIVATE_EXPEDITED_SYNC_CORE => Ok(0),
        _ => Err(LinuxError::EINVAL),
    }
}

pub fn sys_get_mempolicy(
    mode: UserPtr<c_int>,
    nodemask: UserPtr<usize>,
    maxnode: usize,
    _addr: usize,
    flags: usize,
) -> LinuxResult<isize> {
    const MPOL_DEFAULT: c_int = 0;
    const MPOL_F_MEMS_ALLOWED: usize = 1 << 2;

    if flags & !MPOL_F_MEMS_ALLOWED != 0 {
        return Err(LinuxError::EINVAL);
    }
    if !mode.is_null() {
        *mode.get_as_mut()? = MPOL_DEFAULT;
    }
    if !nodemask.is_null() && maxnode > 0 {
        let words = maxnode.div_ceil(usize::BITS as usize);
        let nodemask = nodemask.get_as_mut_slice(words)?;
        nodemask.fill(0);
        nodemask[0] = 1;
    }
    Ok(0)
}

const fn pad_str(info: &str) -> [c_char; 65] {
    let mut data: [c_char; 65] = [0; 65];
    // this needs #![feature(const_copy_from_slice)]
    // data[..info.len()].copy_from_slice(info.as_bytes());
    unsafe {
        core::ptr::copy_nonoverlapping(info.as_ptr().cast(), data.as_mut_ptr(), info.len());
    }
    data
}

