use alloc::sync::Arc;
use core::{
    any::Any,
    ffi::c_int,
    sync::atomic::{AtomicBool, Ordering},
};

use axerrno::{LinuxError, LinuxResult};
use axio::PollState;
use axprocess::{Pid, Process};
use axsignal::{SignalInfo, Signo};
use axtask::{TaskExtRef, current};
use linux_raw_sys::general::{O_NONBLOCK, SI_USER};
use starry_core::task::{ProcessData, get_process};

use crate::{
    file::{FD_TABLE, FileLike, Kstat, add_file_like},
    ptr::{UserConstPtr, nullable},
    signal::send_signal_process,
};

const FD_CLOEXEC: u32 = 1;
const PIDFD_NONBLOCK: u32 = O_NONBLOCK;

pub struct PidFd {
    process: Arc<Process>,
    nonblocking: AtomicBool,
}

impl PidFd {
    fn new(process: Arc<Process>, flags: u32) -> Self {
        Self {
            process,
            nonblocking: AtomicBool::new(flags & PIDFD_NONBLOCK != 0),
        }
    }

    pub fn process(&self) -> Arc<Process> {
        self.process.clone()
    }

    pub fn nonblocking(&self) -> bool {
        self.nonblocking.load(Ordering::Relaxed)
    }
}

impl FileLike for PidFd {
    fn read(&self, _buf: &mut [u8]) -> LinuxResult<usize> {
        Err(LinuxError::EINVAL)
    }

    fn write(&self, _buf: &[u8]) -> LinuxResult<usize> {
        Err(LinuxError::EINVAL)
    }

    fn stat(&self) -> LinuxResult<Kstat> {
        Ok(Kstat::default())
    }

    fn into_any(self: Arc<Self>) -> Arc<dyn Any + Send + Sync> {
        self
    }

    fn poll(&self) -> LinuxResult<PollState> {
        Ok(PollState {
            readable: self.process.is_zombie(),
            writable: false,
        })
    }

    fn set_nonblocking(&self, nonblocking: bool) -> LinuxResult {
        self.nonblocking.store(nonblocking, Ordering::Relaxed);
        Ok(())
    }

    fn descriptor_flags(&self) -> LinuxResult<u32> {
        Ok(FD_CLOEXEC)
    }

    fn status_flags(&self) -> LinuxResult<u32> {
        Ok(if self.nonblocking() {
            PIDFD_NONBLOCK
        } else {
            0
        })
    }
}

pub fn sys_pidfd_open(pid: i32, flags: u32) -> LinuxResult<isize> {
    if pid <= 0 || flags & !PIDFD_NONBLOCK != 0 {
        return Err(LinuxError::EINVAL);
    }

    let process = get_process(pid as Pid)?;
    let current_process = current().task_ext().thread.process();
    if process.pid() != current_process.pid()
        && process
            .parent()
            .is_none_or(|parent| parent.pid() != current_process.pid())
    {
        return Err(LinuxError::ESRCH);
    }

    Ok(PidFd::new(process, flags).add_to_fd_table()? as isize)
}

pub fn pidfd_process(fd: c_int) -> LinuxResult<(Arc<Process>, bool)> {
    let pidfd = PidFd::from_fd(fd)?;
    Ok((pidfd.process(), pidfd.nonblocking()))
}

pub fn sys_pidfd_send_signal(
    fd: c_int,
    signo: u32,
    info: UserConstPtr<SignalInfo>,
    flags: u32,
) -> LinuxResult<isize> {
    if flags != 0 {
        return Err(LinuxError::EINVAL);
    }
    let pidfd = PidFd::from_fd(fd)?;
    let process = pidfd.process();
    if process.is_zombie() {
        return Err(LinuxError::ESRCH);
    }

    let user_info = nullable!(info.get_as_ref())?;
    if signo == 0 {
        return Ok(0);
    }

    let signo = Signo::from_repr(signo as u8).ok_or(LinuxError::EINVAL)?;
    let sig = if let Some(info) = user_info {
        let mut info = info.clone();
        info.set_signo(signo);
        info
    } else {
        SignalInfo::new(signo, SI_USER as _)
    };

    send_signal_process(&process, sig)?;
    Ok(0)
}

pub fn sys_pidfd_getfd(fd: c_int, target_fd: c_int, flags: u32) -> LinuxResult<isize> {
    if flags != 0 {
        return Err(LinuxError::EINVAL);
    }
    if target_fd < 0 {
        return Err(LinuxError::EBADF);
    }

    let pidfd = PidFd::from_fd(fd)?;
    let process = pidfd.process();
    if process.is_zombie() {
        return Err(LinuxError::ESRCH);
    }
    let process_data = process.data::<ProcessData>().ok_or(LinuxError::EPERM)?;
    let file = FD_TABLE
        .deref_from(&process_data.ns)
        .read()
        .get(target_fd as usize)
        .cloned()
        .ok_or(LinuxError::EBADF)?;

    Ok(add_file_like(file)? as isize)
}

use alloc::{sync::Arc, vec::Vec};
use core::{
    any::Any,
    ffi::{c_char, c_int},
    sync::atomic::{AtomicBool, Ordering},
};

use axerrno::{LinuxError, LinuxResult};
use axio::{PollState, SeekFrom};
use axsync::Mutex;

use crate::{
    file::{FileLike, Kstat},
    ptr::UserConstPtr,
};

const MEMFD_NAME_MAX: usize = 249;

const MFD_CLOEXEC: u32 = 0x0001;
const MFD_ALLOW_SEALING: u32 = 0x0002;
const MFD_HUGETLB: u32 = 0x0004;
const MFD_NOEXEC_SEAL: u32 = 0x0008;
const MFD_EXEC: u32 = 0x0010;
const MFD_HUGE_MASK: u32 = 0x3f << 26;
const MFD_KNOWN_MASK: u32 =
    MFD_CLOEXEC | MFD_ALLOW_SEALING | MFD_HUGETLB | MFD_NOEXEC_SEAL | MFD_EXEC | MFD_HUGE_MASK;

pub const F_ADD_SEALS: u32 = 1033;
pub const F_GET_SEALS: u32 = 1034;
pub const F_SEAL_SEAL: u32 = 0x0001;
const F_SEAL_SHRINK: u32 = 0x0002;
const F_SEAL_GROW: u32 = 0x0004;
const F_SEAL_WRITE: u32 = 0x0008;
const F_SEAL_FUTURE_WRITE: u32 = 0x0010;
const F_SEAL_EXEC: u32 = 0x0020;
const F_SEAL_KNOWN_MASK: u32 =
    F_SEAL_SEAL | F_SEAL_SHRINK | F_SEAL_GROW | F_SEAL_WRITE | F_SEAL_FUTURE_WRITE | F_SEAL_EXEC;

struct MemFdInner {
    data: Vec<u8>,
    offset: u64,
    seals: u32,
}

pub struct MemFd {
    inner: Mutex<MemFdInner>,
    nonblocking: AtomicBool,
}

impl MemFd {
    fn new(seals: u32) -> Self {
        Self {
            inner: Mutex::new(MemFdInner {
                data: Vec::new(),
                offset: 0,
                seals,
            }),
            nonblocking: AtomicBool::new(false),
        }
    }

    fn write_locked(inner: &mut MemFdInner, offset: u64, buf: &[u8]) -> LinuxResult<usize> {
        if inner.seals & (F_SEAL_WRITE | F_SEAL_FUTURE_WRITE) != 0 {
            return Err(LinuxError::EPERM);
        }

        let start = usize::try_from(offset).map_err(|_| LinuxError::EINVAL)?;
        let end = start.checked_add(buf.len()).ok_or(LinuxError::EINVAL)?;
        if end > inner.data.len() {
            if inner.seals & F_SEAL_GROW != 0 {
                return Err(LinuxError::EPERM);
            }
            inner.data.resize(end, 0);
        }
        inner.data[start..end].copy_from_slice(buf);
        Ok(buf.len())
    }
}

impl FileLike for MemFd {
    fn read(&self, buf: &mut [u8]) -> LinuxResult<usize> {
        let mut inner = self.inner.lock();
        let start = usize::try_from(inner.offset).map_err(|_| LinuxError::EINVAL)?;
        if start >= inner.data.len() {
            return Ok(0);
        }
        let read = core::cmp::min(buf.len(), inner.data.len() - start);
        buf[..read].copy_from_slice(&inner.data[start..start + read]);
        inner.offset = inner.offset.saturating_add(read as u64);
        Ok(read)
    }

    fn write(&self, buf: &[u8]) -> LinuxResult<usize> {
        let mut inner = self.inner.lock();
        let offset = inner.offset;
        let written = Self::write_locked(&mut inner, offset, buf)?;
        inner.offset = inner.offset.saturating_add(written as u64);
        Ok(written)
    }

    fn stat(&self) -> LinuxResult<Kstat> {
        Ok(Kstat::regular(self.inner.lock().data.len() as u64, 0o600))
    }

    fn into_any(self: Arc<Self>) -> Arc<dyn Any + Send + Sync> {
        self
    }

    fn poll(&self) -> LinuxResult<PollState> {
        Ok(PollState {
            readable: true,
            writable: true,
        })
    }

    fn set_nonblocking(&self, nonblocking: bool) -> LinuxResult {
        self.nonblocking.store(nonblocking, Ordering::Relaxed);
        Ok(())
    }

    fn read_at(&self, offset: u64, buf: &mut [u8]) -> LinuxResult<usize> {
        let inner = self.inner.lock();
        let start = usize::try_from(offset).map_err(|_| LinuxError::EINVAL)?;
        if start >= inner.data.len() {
            return Ok(0);
        }
        let len = core::cmp::min(buf.len(), inner.data.len() - start);
        buf[..len].copy_from_slice(&inner.data[start..start + len]);
        Ok(len)
    }

    fn write_at(&self, offset: u64, buf: &[u8]) -> LinuxResult<usize> {
        let mut inner = self.inner.lock();
        Self::write_locked(&mut inner, offset, buf)
    }

    fn seek(&self, pos: SeekFrom) -> LinuxResult<u64> {
        let mut inner = self.inner.lock();
        let next = match pos {
            SeekFrom::Start(offset) => offset as i128,
            SeekFrom::Current(offset) => inner.offset as i128 + offset as i128,
            SeekFrom::End(offset) => inner.data.len() as i128 + offset as i128,
        };
        if next < 0 || next > u64::MAX as i128 {
            return Err(LinuxError::EINVAL);
        }
        inner.offset = next as u64;
        Ok(inner.offset)
    }

    fn truncate(&self, length: u64) -> LinuxResult {
        let mut inner = self.inner.lock();
        let length = usize::try_from(length).map_err(|_| LinuxError::EINVAL)?;
        if length < inner.data.len() && inner.seals & F_SEAL_SHRINK != 0 {
            return Err(LinuxError::EPERM);
        }
        if length > inner.data.len() && inner.seals & F_SEAL_GROW != 0 {
            return Err(LinuxError::EPERM);
        }
        inner.data.resize(length, 0);
        Ok(())
    }

    fn add_seals(&self, seals: u32) -> LinuxResult {
        if seals & !F_SEAL_KNOWN_MASK != 0 {
            return Err(LinuxError::EINVAL);
        }
        let mut inner = self.inner.lock();
        if inner.seals & F_SEAL_SEAL != 0 {
            return Err(LinuxError::EPERM);
        }
        inner.seals |= seals;
        Ok(())
    }

    fn get_seals(&self) -> LinuxResult<u32> {
        Ok(self.inner.lock().seals)
    }
}

pub fn sys_memfd_create(name: UserConstPtr<c_char>, flags: c_int) -> LinuxResult<isize> {
    let flags = flags as u32;
    if flags & !MFD_KNOWN_MASK != 0 {
        return Err(LinuxError::EINVAL);
    }
    if flags & MFD_HUGE_MASK != 0 && flags & MFD_HUGETLB == 0 {
        return Err(LinuxError::EINVAL);
    }
    if flags & MFD_HUGETLB != 0 {
        return Err(LinuxError::ENODEV);
    }
    if flags & MFD_NOEXEC_SEAL != 0 && flags & MFD_EXEC != 0 {
        return Err(LinuxError::EINVAL);
    }

    let name = name.get_as_str()?;
    if name.len() > MEMFD_NAME_MAX {
        return Err(LinuxError::EINVAL);
    }

    let mut seals = if flags & MFD_ALLOW_SEALING != 0 {
        0
    } else {
        F_SEAL_SEAL
    };
    if flags & MFD_NOEXEC_SEAL != 0 {
        seals |= F_SEAL_EXEC;
    }

    Ok(MemFd::new(seals).add_to_fd_table()? as isize)
}
